class Solution {
public:
    string solveEquation(string equation) {
        int x = 0, y = 0, sign = 1;
        int n = equation.size();
        for (int i = 0; i < n; i++) {
            if (equation[i] == '=') {
                break;
            }
            if (equation[i] == '+' || equation[i] == '-') {
                if (equation[i] == '-') {
                    sign = -1;
                } else {
                    sign = 1;
                }
                i++;
                while (i < n && isdigit(equation[i])) {
                    x = x * 10 + (equation[i++] - '0');
                }
                x *= sign;
            }
        }
        sign = 1;
        for (int i = equation.find('=') + 1; i < n; i++) {
            if (equation[i] == '+' || equation[i] == '-') {
                if (equation[i] == '-') {
                    sign = -1;
                } else {
                    sign = 1;
                }
                i++;
                while (i < n && isdigit(equation[i])) {
                    y = y * 10 + (equation[i++] - '0');
                }
                y *= sign;
            }
        }
        if (x == y) {
            return "Infinite solutions";
        }
        x = (y - x);
        if (x == 0) {
            return "No solution";
        }
        return "x=" + to_string(x);
    }
};
```

